import sys
from functools import lru_cache
input = sys.stdin.readline

def count_liked(n):
    """计算 [1, n] 中不含数字3且不被3整除的正整数个数"""
    if n <= 0:
        return 0
    digits = list(map(int, str(n)))
    L = len(digits)

    @lru_cache(maxsize=None)
    def dp(pos, tight, mod, started):
        if pos == L:
            return 1 if started and mod != 0 else 0
        limit = digits[pos] if tight else 9
        res = 0
        for d in range(0, limit + 1):
            if d == 3:
                continue
            new_started = started or d > 0
            new_mod = (mod + d) % 3 if new_started else 0
            res += dp(pos + 1, tight and d == limit, new_mod, new_started)
        return res

    return dp(0, True, 0, False)

def solve():
    t = int(input())
    for _ in range(t):
        k = int(input())
        lo, hi = 1, 2 * 10**18
        while lo < hi:
            mid = (lo + hi) // 2
            if count_liked(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        count_liked.cache_clear()
        print(lo)

solve()
